import React from "react";

export default function AddNew({ setView }) {
  return (
    <div
      style={{
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        paddingTop: "50px",
      }}
    >
      {/* PAGE TITLE */}
      <h1
        style={{
          fontSize: "28px",
          marginBottom: "40px",
          color: "#0f9d58",
          fontWeight: "600",
        }}
      >
        Add New Expense
      </h1>

      {/* CARD CONTAINER */}
      <div
        style={{
          display: "flex",
          gap: "40px",
          justifyContent: "center",
        }}
      >
        {/* TRAVEL EXPENSE CARD */}
        <div
          onClick={() => setView("travel")}
          style={{
            width: "260px",
            height: "200px",
            background: "#0f9d58",
            color: "white",
            borderRadius: "20px",
            display: "flex",
            flexDirection: "column",
            justifyContent: "center",
            alignItems: "center",
            cursor: "pointer",
            fontSize: "22px",
            fontWeight: "600",
            boxShadow: "0 8px 20px rgba(0,0,0,0.2)",
            transition: "0.3s",
          }}
          onMouseOver={(e) => (e.currentTarget.style.transform = "scale(1.05)")}
          onMouseOut={(e) => (e.currentTarget.style.transform = "scale(1)")}
        >
          🚌
          <br />
          Travel Expense
        </div>

        {/* TICKET EXPENSE CARD */}
        <div
          onClick={() => setView("ticket")}
          style={{
            width: "260px",
            height: "200px",
            background: "#0078d4",
            color: "white",
            borderRadius: "20px",
            display: "flex",
            flexDirection: "column",
            justifyContent: "center",
            alignItems: "center",
            cursor: "pointer",
            fontSize: "22px",
            fontWeight: "600",
            boxShadow: "0 8px 20px rgba(0,0,0,0.2)",
            transition: "0.3s",
          }}
          onMouseOver={(e) => (e.currentTarget.style.transform = "scale(1.05)")}
          onMouseOut={(e) => (e.currentTarget.style.transform = "scale(1)")}
        >
          🎫
          <br />
          Ticket Expense
        </div>
      </div>
    </div>
  );
}
